  // Dados do clip Vizard
  vizard_video_id:   Number(clip.videoId) || null,
  clip_url:          clip.videoUrl || '',
  titulo_sugerido:   clip.title || '',
  transcricao:       clip.transcript || '',
  duracao:           Math.round((Number(clip.videoMsDuration) || 0) / 1000),
  score:             Number(clip.viralScore) || 0,
  viral_reason:      clip.viralReason || ''
} }];

