// Combina parse de título/descrição/hashtags E keywords em um único nó
const clipData = $('loop-by-clip').item.json;
const aiRaw = $input.first().json;

let enhanced = {
  titulo_final:       clipData.titulo_sugerido || clipData.titulo_original || 'Sem título',
  descricao_base:     'Confira este conteúdo!',
  hashtags:           ['#shorts', '#viral', '#fy'],
  sugestao_thumbnail: 'IMPERDÍVEL',
  gancho_abertura:    '',
  keywords:           []
};

try {
  let text = '';
  if (typeof aiRaw.content === 'string' && aiRaw.content.trim())    text = aiRaw.content;
  else if (typeof aiRaw.text === 'string' && aiRaw.text.trim())     text = aiRaw.text;
  else if (typeof aiRaw.output === 'string' && aiRaw.output.trim()) text = aiRaw.output;
  else if (aiRaw.message?.content)                                   text = aiRaw.message.content;

  text = text.replace(/```json\s*|```/g, '').trim();

  let parsed = null;
  if (text.startsWith('{')) {
    parsed = JSON.parse(text);
  } else {
    const i = text.indexOf('{');
    const j = text.lastIndexOf('}');
    if (i !== -1 && j > i) parsed = JSON.parse(text.slice(i, j + 1));
  }

  if (parsed) enhanced = { ...enhanced, ...parsed };
} catch (e) { /* usa fallback */ }

const sanitize = (s) => String(s || '').replace(/'/g, "''");

let titulo = String(enhanced.titulo_final || '');
if (titulo.length > 60) titulo = titulo.substring(0, 57) + '...';

const hashtagsArr = Array.isArray(enhanced.hashtags)
  ? enhanced.hashtags.map(h => h.startsWith('#') ? h : `#${h}`)
  : ['#shorts'];

let keywords = Array.isArray(enhanced.keywords)
  ? enhanced.keywords.map(k => String(k).toLowerCase().trim()).filter(Boolean)
  : [];

if (keywords.length === 0) {
  const base = [clipData.nicho || ''];
  const titleWords = titulo.split(/\s+/).map(w => w.toLowerCase()).filter(w => w.length > 4);
  keywords = [...base, ...titleWords.slice(0, 4)].filter(Boolean);
}

const keywordsSql = keywords.map(k => sanitize(k)).join("','");

return [{
  json: {
    ...clipData,
    titulo_final:       sanitize(titulo),
    descricao_base:     sanitize(String(enhanced.descricao_base || '')),
    hashtags:           hashtagsArr,
    sugestao_thumbnail: sanitize(String(enhanced.sugestao_thumbnail || '')),
    gancho_abertura:    sanitize(String(enhanced.gancho_abertura || '')),
    extracted_keywords: keywords,
    keywords_sql:       keywordsSql
  }
}];

const clipData = $('parse-ai-response').item.json;
const links = $('fetch-affiliate-links').all();
const monetConfig = $('fetch-monetization-config').item?.json || {};

let blocoMonetizacao = '';

const linksValidos = links.filter(l => l.json && l.json.url);
if (linksValidos.length > 0) {
  blocoMonetizacao = '\n\n---';
  for (const link of linksValidos) {
    const l = link.json;
    const emoji = l.tipo === 'amazon'          ? '📚'
                : l.tipo === 'hotmart'         ? '🎓'
                : l.tipo === 'produto_proprio' ? '🚀'
                : '🔗';
    blocoMonetizacao += `\n${emoji} ${l.descricao_curta}: ${l.url}`;
  }
}

if (monetConfig.link_leads) {
  blocoMonetizacao += `\n\n📩 Acesse conteúdo exclusivo: ${monetConfig.link_leads}`;
}

const hashtagsStr = (clipData.hashtags || [])
  .map(h => h.startsWith('#') ? h : `#${h}`)
  .join(' ');

const descricaoFinal = `${clipData.descricao_base}${blocoMonetizacao}\n\n${hashtagsStr}`;

const sanitize = (s) => String(s || '').replace(/'/g, "''");

return [{
  json: {
    ...clipData,
    descricao_final: sanitize(descricaoFinal),
    hashtags_str:    sanitize(hashtagsStr),
    links_incluidos: linksValidos.length
  }
}];

const body = $json.body || {};
const projectId = body.projectId || null;
const code = Number(body.code || 0);
const videos = Array.isArray(body.videos) ? body.videos : [];

return [{
  json: {
    code,
    projectId,
    projectName: body.projectName || '',
    creditsUsed: body.creditsUsed ?? null,
    videos
  }
}];

